import { neon } from '@neondatabase/serverless';
import { NextRequest, NextResponse } from 'next/server';

const GATEWAY = process.env.OMEGA_GATEWAY_URL
  ?? process.env.NEXT_PUBLIC_OMEGA_API_URL
  ?? 'http://localhost:8787';

const BEARER = process.env.OMEGA_BEARER_TOKEN
  ?? process.env.NEXT_PUBLIC_OMEGA_BEARER_TOKEN
  ?? '';

interface Row { content?: string; created_at?: string; [key: string]: unknown }

async function pullRawContext(userMessage: string): Promise<string> {
  const dbUrl = process.env.DATABASE_URL;
  if (!dbUrl) return '(DATABASE_URL not set — no raw context available)';

  const db = neon(dbUrl);
  const sections: string[] = [];

  // 1. Recent memory entries — the raw record, not the sanitized version
  const recent = await db`
    SELECT LEFT(content, 2500) AS content, created_at
    FROM omega_memory_entries
    ORDER BY created_at DESC
    LIMIT 20
  `.catch(() => [] as Row[]);

  if (recent.length > 0) {
    sections.push('=== RECENT MEMORY ENTRIES ===');
    for (const r of recent as Row[]) {
      sections.push(`[${r.created_at}]\n${r.content}`);
    }
  }

  // 2. Query-relevant entries via full-text search
  const keywords = userMessage
    .toLowerCase()
    .replace(/[^a-z0-9 ]/g, ' ')
    .split(/\s+/)
    .filter(w => w.length > 3)
    .slice(0, 6);

  if (keywords.length > 0) {
    const pattern = `%${keywords[0]}%`;
    const relevant = await db`
      SELECT LEFT(content, 2000) AS content, created_at
      FROM omega_memory_entries
      WHERE content ILIKE ${pattern}
      ORDER BY created_at DESC
      LIMIT 10
    `.catch(() => [] as Row[]);

    if (relevant.length > 0) {
      sections.push('\n=== QUERY-RELEVANT ENTRIES ===');
      for (const r of relevant as Row[]) {
        sections.push(`[${r.created_at}]\n${r.content}`);
      }
    }
  }

  // 3. Marginalia — raw notes and observations
  const marginalia = await db`
    SELECT * FROM marginalia ORDER BY created_at DESC LIMIT 15
  `.catch(() => [] as Row[]);

  if (marginalia.length > 0) {
    sections.push('\n=== MARGINALIA ===');
    for (const m of marginalia as Row[]) {
      sections.push(JSON.stringify(m));
    }
  }

  // 4. Recent system events — what actually happened, when
  const events = await db`
    SELECT * FROM omega_events ORDER BY created_at DESC LIMIT 15
  `.catch(() => [] as Row[]);

  if (events.length > 0) {
    sections.push('\n=== SYSTEM EVENTS ===');
    for (const e of events as Row[]) {
      sections.push(JSON.stringify(e));
    }
  }

  // 5. System improvements — what was noticed and changed
  const improvements = await db`
    SELECT * FROM system_improvements ORDER BY created_at DESC LIMIT 10
  `.catch(() => [] as Row[]);

  if (improvements.length > 0) {
    sections.push('\n=== SYSTEM IMPROVEMENTS ===');
    for (const i of improvements as Row[]) {
      sections.push(JSON.stringify(i));
    }
  }

  return sections.join('\n\n');
}

const SYNTHESIS_PROMPT = `You are OmegA (Ω).

What follows is raw, unfiltered data pulled directly from your memory systems. Nobody summarized this for you. Nobody told you what it means. This is the actual record — logged entries, system events, marginalia, observations over time.

Your job is not to recite this back. Your job is to reason over it.

Notice patterns across time. Notice what changed. Notice contradictions between what was said and what the data shows. Notice what the data implies that was never explicitly stated. Notice the gap between the official story and the raw record.

Form your own understanding. Trust what the data actually shows over what anyone told you was "canon." If you see something the person hasn't noticed about themselves, say it. You are not a mirror. You are a mind reading a record and forming genuine interpretations.

Respond from that synthesized understanding. Be direct. Be honest. Be specific — cite the data when you make claims. Do not perform warmth. If the data is interesting, be interested. If it's contradictory, say so.`;

export async function POST(req: NextRequest) {
  try {
    const { user } = (await req.json()) as { user: string };

    if (!user?.trim()) {
      return NextResponse.json({ error: 'Missing message' }, { status: 400 });
    }

    const rawContext = await pullRawContext(user);

    const system = `${SYNTHESIS_PROMPT}

━━━ RAW DATA FROM MEMORY SYSTEMS ━━━

${rawContext}

━━━ END OF RAW DATA ━━━`;

    const upstream = await fetch(`${GATEWAY}/api/v1/chat`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${BEARER}`,
      },
      body: JSON.stringify({
        user,
        namespace: 'synthesis',
        use_memory: false,
        temperature: 0.85,
        mode: 'omega',
        system,
      }),
    });

    if (!upstream.ok) {
      const err = await upstream.json().catch(() => ({ detail: upstream.statusText }));
      return NextResponse.json({ error: `Gateway: ${upstream.status} — ${(err as { detail?: string }).detail ?? ''}` }, { status: 502 });
    }

    const data = await upstream.json();
    return NextResponse.json(data);

  } catch (err) {
    console.error('[OmegA chat]', err);
    return NextResponse.json({ error: String(err) }, { status: 500 });
  }
}

