/* ── Shell ──────────────────────────────────────────────────────────────── */
.shell {
  display: flex;
  flex-direction: column;
  height: 100dvh;
  max-width: 800px;
  margin: 0 auto;
  padding: 0 1rem;
}

/* ── Header ─────────────────────────────────────────────────────────────── */
.header {
  display: flex;
  align-items: center;
  gap: 0.6rem;
  padding: 1.2rem 0;
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
  flex-shrink: 0;
}

.omega {
  font-size: 1.6rem;
  color: var(--omega-cyan);
  line-height: 1;
}

.name {
  font-size: 1.1rem;
  font-weight: 600;
  letter-spacing: 0.08em;
  color: rgba(255, 255, 255, 0.85);
}

/* ── Feed ───────────────────────────────────────────────────────────────── */
.feed {
  flex: 1;
  overflow-y: auto;
  padding: 1.5rem 0;
  display: flex;
  flex-direction: column;
  gap: 1.2rem;
}

/* ── Empty state ────────────────────────────────────────────────────────── */
.empty {
  margin: auto;
  text-align: center;
  max-width: 480px;
  padding: 2rem 1rem;
}

.emptyTitle {
  font-size: 1.6rem;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.9);
  margin-bottom: 0.75rem;
}

.emptySubtitle {
  font-size: 1rem;
  color: rgba(255, 255, 255, 0.35);
  line-height: 1.65;
}

/* ── Bubbles ────────────────────────────────────────────────────────────── */
.bubbleUser {
  align-self: flex-end;
  max-width: 72%;
  background: rgba(0, 212, 212, 0.12);
  border: 1px solid rgba(0, 212, 212, 0.2);
  border-radius: 1.2rem 1.2rem 0.25rem 1.2rem;
  padding: 0.8rem 1.1rem;
}

.bubbleOmega {
  align-self: flex-start;
  max-width: 80%;
  display: flex;
  gap: 0.65rem;
  align-items: flex-start;
}

.bubbleLabel {
  color: var(--omega-cyan);
  font-size: 1rem;
  font-weight: 700;
  flex-shrink: 0;
  padding-top: 0.05rem;
}

.bubbleText {
  color: rgba(255, 255, 255, 0.88);
  font-size: 1rem;
  line-height: 1.7;
  white-space: pre-wrap;
  margin: 0;
}

.thinking {
  color: rgba(255, 255, 255, 0.3);
  font-size: 1rem;
  font-style: italic;
  margin: 0;
  animation: pulse 1.4s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 0.3; }
  50%       { opacity: 0.7; }
}

/* ── Error ──────────────────────────────────────────────────────────────── */
.error {
  color: #ff6b6b;
  font-size: 0.9rem;
  padding: 0 0.5rem;
}

/* ── Input row ──────────────────────────────────────────────────────────── */
.inputRow {
  display: flex;
  gap: 0.6rem;
  align-items: flex-end;
  padding: 1rem 0 1.5rem;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
  flex-shrink: 0;
}

.input {
  flex: 1;
  padding: 0.75rem 1rem;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 0.75rem;
  color: rgba(255, 255, 255, 0.9);
  font-family: inherit;
  font-size: 1rem;
  line-height: 1.5;
  resize: none;
  outline: none;
  transition: border-color 0.2s;
  max-height: 160px;
  overflow-y: auto;
}

.input:focus {
  border-color: rgba(0, 212, 212, 0.5);
}

.input::placeholder {
  color: rgba(255, 255, 255, 0.2);
}

.sendBtn {
  width: 2.6rem;
  height: 2.6rem;
  border-radius: 50%;
  background: var(--omega-cyan);
  color: #000;
  font-size: 1.1rem;
  font-weight: 700;
  border: none;
  cursor: pointer;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.2s, transform 0.15s;
}

.sendBtn:hover:not(:disabled) {
  background: var(--sovereign-gold);
  transform: translateY(-1px);
}

.sendBtn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

