/* ── Root ───────────────────────────────────────────────────────── */
.root {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  z-index: 1;
}

/* ── Landing ────────────────────────────────────────────────────── */
.landing {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0;
  padding-bottom: 120px;
}

.landingOmega {
  font-family: 'Orbitron', sans-serif;
  font-size: clamp(96px, 22vw, 180px);
  font-weight: 900;
  color: var(--gold);
  line-height: 1;
  user-select: none;
  animation: omega-breathe 4s ease-in-out infinite;
  transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
  letter-spacing: -0.02em;
}

.landingOmega.thinking {
  animation: omega-think 1.1s ease-in-out infinite;
}

.landingOmega.responding {
  animation: omega-respond 1.5s ease-out forwards;
}

.landingTitle {
  font-family: 'Orbitron', sans-serif;
  font-size: clamp(13px, 3vw, 17px);
  font-weight: 400;
  letter-spacing: 0.42em;
  color: var(--dimmer);
  text-transform: uppercase;
  margin-top: 0.6rem;
}

.landingTagline {
  font-size: clamp(14px, 3.5vw, 16px);
  color: var(--dimmer);
  margin-top: 2rem;
  letter-spacing: 0.04em;
  font-weight: 300;
}

/* Ring pulse on think */
.ringWrap {
  position: absolute;
  pointer-events: none;
}

.ring {
  position: absolute;
  border-radius: 50%;
  border: 1px solid rgba(228, 184, 74, 0.4);
  width: 220px;
  height: 220px;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  animation: ring-pulse 2s ease-out infinite;
}

.ring:nth-child(2) { animation-delay: 0.5s; }
.ring:nth-child(3) { animation-delay: 1s; }

/* ── Header (chat mode) ─────────────────────────────────────────── */
.header {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 1rem 1.5rem;
  border-bottom: 1px solid rgba(139, 92, 246, 0.12);
  background: rgba(2, 2, 18, 0.8);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  flex-shrink: 0;
  animation: fade-up 0.4s ease;
}

.headerOmega {
  font-family: 'Orbitron', sans-serif;
  font-size: 1.5rem;
  font-weight: 900;
  color: var(--gold);
  animation: omega-breathe 4s ease-in-out infinite;
  line-height: 1;
}

.headerOmega.thinking {
  animation: omega-think 1.1s ease-in-out infinite;
}

.headerName {
  font-family: 'Orbitron', sans-serif;
  font-size: 0.8rem;
  letter-spacing: 0.35em;
  color: var(--dimmer);
  text-transform: uppercase;
}

.headerStatus {
  margin-left: auto;
  display: flex;
  align-items: center;
  gap: 0.4rem;
  font-size: 0.72rem;
  letter-spacing: 0.08em;
  color: rgba(196, 181, 253, 0.4);
  text-transform: uppercase;
}

.statusDot {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: #4ade80;
  box-shadow: 0 0 6px #4ade80;
}

/* ── Feed ───────────────────────────────────────────────────────── */
.feed {
  flex: 1;
  overflow-y: auto;
  padding: 1.5rem 1rem 0;
  display: flex;
  flex-direction: column;
  gap: 1.6rem;
  max-width: 820px;
  width: 100%;
  margin: 0 auto;
}

/* ── Messages ───────────────────────────────────────────────────── */
.msgUser {
  align-self: flex-end;
  max-width: 75%;
  background: rgba(99, 102, 241, 0.1);
  border: 1px solid rgba(99, 102, 241, 0.22);
  border-radius: 1.4rem 1.4rem 0.3rem 1.4rem;
  padding: 0.85rem 1.2rem;
  color: rgba(241, 245, 249, 0.88);
  font-size: 0.97rem;
  line-height: 1.65;
  animation: fade-up 0.3s ease;
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}

.msgOmega {
  align-self: flex-start;
  max-width: 88%;
  display: flex;
  gap: 0.9rem;
  align-items: flex-start;
  animation: fade-up 0.4s ease;
}

.omegaGlyph {
  font-family: 'Orbitron', sans-serif;
  font-size: 1.1rem;
  font-weight: 900;
  color: var(--gold);
  flex-shrink: 0;
